#include <iostream>
using namespace std;

class Rectangle {
public:
 int width;
 int height;
};

int main() {
 // Declare pointer to int member of Rectangle
 int Rectangle::*wptr = &Rectangle::width;
 int Rectangle::*hptr = &Rectangle::height;

 Rectangle rect = {10, 5};

 // Access through object using .*
 cout << "Width: " << rect.*wptr << endl;
 cout << "Height: " << rect.*hptr << endl;

 // Modify using pointer
 rect.*wptr = 20;
 cout << "New Width: " << rect.width << endl;

 return 0;
}

#include <iostream>
using namespace std;

class Calculator {
public:
 int add(int a, int b) { return a + b; }
 int subtract(int a, int b) { return a - b; }
 int multiply(int a, int b) { return a * b; }
};

int main() {
 // Declare pointer to member function
 int (Calculator::*opPtr)(int, int);

 Calculator calc;

 // Point to different functions
 opPtr = &Calculator::add;
 cout << "Add: " << (calc.*opPtr)(10, 5) << endl;

 opPtr = &Calculator::subtract;
 cout << "Subtract: " << (calc.*opPtr)(10, 5) << endl;

 opPtr = &Calculator::multiply;
 cout << "Multiply: " << (calc.*opPtr)(10, 5) << endl;

 return 0;
}

#include <iostream>
using namespace std;

class Calculator {
private:
 int result;
public:
 Calculator() : result(0) {}

 void add(int v) { result += v; }
 void subtract(int v) { result -= v; }
 void multiply(int v) { result *= v; }
 void divide(int v) { if(v != 0) result /= v; }
 void clear() { result = 0; }
 void display() { cout << "Result: " << result << endl; }
};

int main() {
 Calculator calc;

 // Array of pointers to member functions
 void (Calculator::*operations[4])(int) = {
 &Calculator::add,
 &Calculator::subtract,
 &Calculator::multiply,
 &Calculator::divide
 };

 int choice, value;

 calc.add(10); // Initial value
 calc.display();

 cout << "Enter operation (0=add,1=sub,2=mul,3=div): ";
 cin >> choice;
 cout << "Enter value: ";
 cin >> value;

 if(choice >= 0 && choice < 4) {
 (calc.*operations[choice])(value);
 calc.display();
 }

 return 0;
}

#include <iostream>
using namespace std;

class MyClass {
public:
 int data;
 int getData() { return data; }
 void setData(int v) { data = v; }
};

// Typedef for pointer to data member
typedef int MyClass::*IntDataPtr;

// Typedef for pointer to member function
typedef int (MyClass::*GetterFn)();
typedef void (MyClass::*SetterFn)(int);

int main() {
 IntDataPtr dataPtr = &MyClass::data;
 GetterFn getFn = &MyClass::getData;
 SetterFn setFn = &MyClass::setData;

 MyClass obj;

 // Using typedef names
 (obj.*setFn)(42);
 cout << "Data: " << (obj.*getFn)() << endl;
 cout << "Direct: " << obj.*dataPtr << endl;

 return 0;
}
